parameters.jsCode:
// Parse Slack interaction payload
const payload = $input.first().json.body.payload;
let parsedPayload;

if (typeof payload === 'string') {
  parsedPayload = JSON.parse(payload);
} else {
  parsedPayload = payload;
}

// Extract basic action details
const action = parsedPayload.actions?.[0];
const actionId = action?.action_id; 
const user = parsedPayload.user;
const channel = parsedPayload.channel;
const responseUrl = parsedPayload.response_url;
const messageTs = parsedPayload.message?.ts;

// Logic to extract Bird IDs from the pipe-separated value
// Example: "9417efce...|7a2155ed...|6e133ad8..."
const rawValue = action?.value || "";
const valueParts = rawValue.split('|');

const birdConversationId = valueParts[0] || null;

// Helper function to extract text from markdown fields
function extractFromField(blocks, label) {
  for (const block of blocks) {
    if (block.type === 'section' && block.fields) {
      for (const field of block.fields) {
        if (field.text && field.text.includes(label)) {
          const parts = field.text.split('\n');
          if (parts.length > 1) {
            return parts[1].trim();
          }
        }
      }
    }
  }
  return null;
}

// Helper function to extract text inside code blocks
function extractSectionText(blocks, header) {
  for (const block of blocks) {
    if (block.type === 'section' && block.text && block.text.text) {
      if (block.text.text.includes(header)) {
        const text = block.text.text;
        const codeBlockMatch = text.match(/```([\s\S]*?)```/);
        if (codeBlockMatch) {
          return codeBlockMatch[1].trim();
        }
        const parts = text.split(header);
        if (parts.length > 1) {
          return parts[1].replace(/^\n/, '').trim();
        }
      }
    }
  }
  return null;
}

const blocks = parsedPayload.message?.blocks || [];

// Extraction based on the specific keys in your JSON payload
const restaurantName = extractFromField(blocks, '*Restaurant:*');
const number = extractFromField(blocks, '*Number:*');
const contactName = extractFromField(blocks, '*Contact name:*');
const leadMessage = extractSectionText(blocks, "*Prospect's Reply:*");
const aiResponse = extractSectionText(blocks, '*Agent Generated Response:*');

return {
  json: {
    action_id: actionId,
    bird_conversation_id: birdConversationId,
    slack_channel_id: channel?.id,
    slack_channel_name: channel?.name,
    slack_user_id: user?.id,
    slack_user_name: user?.name || user?.username,
    company_name: restaurantName,
    contact_name: contactName || 'Unknown',
    lead_identifier: number,
    message_type: "block_actions",
    lead_message: leadMessage,
    ai_generated_response: aiResponse,
    response_url: responseUrl,
    original_message_ts: messageTs
  }
};

